import { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import API from '../services/axios';

function MyBookings() {
  const [bookings, setBookings] = useState([]);
  const [loading, setLoading] = useState(true);
  const [selectedBooking, setSelectedBooking] = useState(null);
  const [paymentMethod, setPaymentMethod] = useState('card');
  const [paymentLoading, setPaymentLoading] = useState(false);

  useEffect(() => { fetchBookings(); }, []);

  const fetchBookings = async () => {
    try {
      const res = await API.get('/bookings/my');
      setBookings(res.data.bookings || []);
    } catch { } finally { setLoading(false); }
  };

  const handleCancel = async (id) => {
    if (!window.confirm('Cancel this booking?')) return;
    try { await API.put(`/bookings/${id}/cancel`, {}); fetchBookings(); }
    catch { alert('Failed to cancel'); }
  };

  const handlePayment = async () => {
    setPaymentLoading(true);
    try {
      await API.post('/payments', { bookingId: selectedBooking._id, paymentMethod });
      setSelectedBooking(null); fetchBookings();
    } catch (err) { alert(err.response?.data?.message || 'Payment failed'); }
    finally { setPaymentLoading(false); }
  };

  if (loading) return (
    <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'center', minHeight: '60vh' }}>
      <div style={{ textAlign: 'center', color: 'white' }}>
        <div style={{ fontSize: '3rem', marginBottom: '1rem' }}>🎫</div>
        <p>Loading bookings...</p>
      </div>
    </div>
  );

  return (
    <div style={{ maxWidth: '900px', margin: '0 auto', padding: '2rem' }}>
      <h1 style={{ color: 'white', fontSize: '2rem', fontWeight: '800', marginBottom: '0.5rem' }}>My Bookings</h1>
      <p style={{ color: 'rgba(255,255,255,0.5)', marginBottom: '2rem' }}>{bookings.length} booking(s)</p>

      {bookings.length === 0 ? (
        <div style={{ background: 'rgba(255,255,255,0.07)', borderRadius: '16px', padding: '4rem', textAlign: 'center' }}>
          <div style={{ fontSize: '3rem', marginBottom: '1rem' }}>🎫</div>
          <p style={{ color: 'rgba(255,255,255,0.5)', marginBottom: '1.5rem' }}>No bookings yet</p>
          <Link to="/home" style={{ background: 'linear-gradient(135deg, #7c3aed, #a78bfa)', color: 'white', padding: '12px 28px', borderRadius: '12px', textDecoration: 'none', fontWeight: '600' }}>
            Browse Events
          </Link>
        </div>
      ) : (
        <div style={{ display: 'flex', flexDirection: 'column', gap: '1rem' }}>
          {bookings.map(booking => (
            <div key={booking._id} style={{ background: 'rgba(255,255,255,0.07)', backdropFilter: 'blur(20px)', border: '1px solid rgba(255,255,255,0.12)', borderRadius: '16px', padding: '1.2rem', display: 'flex', gap: '1rem', alignItems: 'center', flexWrap: 'wrap' }}>
              <img src={booking.event?.image || 'https://via.placeholder.com/120x80?text=Event'}
                alt={booking.event?.name} style={{ width: '120px', height: '80px', objectFit: 'cover', borderRadius: '10px', flexShrink: 0 }} />
              <div style={{ flex: 1, minWidth: '200px' }}>
                <h3 style={{ color: 'white', fontWeight: '700', marginBottom: '4px' }}>{booking.event?.name}</h3>
                <p style={{ color: 'rgba(255,255,255,0.5)', fontSize: '0.8rem' }}>📍 {booking.event?.venue} • 🎫 {booking.numberOfTickets} tickets</p>
                <p style={{ color: '#a78bfa', fontWeight: '700', marginTop: '4px' }}>₹{booking.totalAmount}</p>
                <div style={{ display: 'flex', gap: '8px', marginTop: '8px' }}>
                  {[
                    { label: booking.status, color: booking.status === 'confirmed' ? '#065f46' : booking.status === 'pending' ? '#92400e' : '#991b1b', bg: booking.status === 'confirmed' ? '#d1fae5' : booking.status === 'pending' ? '#fef3c7' : '#fee2e2' },
                    { label: booking.paymentStatus, color: booking.paymentStatus === 'paid' ? '#065f46' : '#991b1b', bg: booking.paymentStatus === 'paid' ? '#d1fae5' : '#fee2e2' }
                  ].map((badge, i) => (
                    <span key={i} style={{ padding: '3px 10px', borderRadius: '20px', fontSize: '0.7rem', fontWeight: '700', background: badge.bg, color: badge.color }}>{badge.label.toUpperCase()}</span>
                  ))}
                </div>
              </div>
              <div style={{ display: 'flex', flexDirection: 'column', gap: '8px' }}>
                {booking.paymentStatus === 'unpaid' && booking.status !== 'cancelled' && (
                  <button onClick={() => setSelectedBooking(booking)} style={{ background: 'linear-gradient(135deg, #059669, #10b981)', color: 'white', border: 'none', padding: '8px 18px', borderRadius: '8px', cursor: 'pointer', fontWeight: '600', fontSize: '0.8rem' }}>
                    💳 Pay Now
                  </button>
                )}
                {booking.status !== 'cancelled' && (
                  <button onClick={() => handleCancel(booking._id)} style={{ background: 'rgba(239,68,68,0.15)', color: '#ef4444', border: '1px solid rgba(239,68,68,0.3)', padding: '8px 18px', borderRadius: '8px', cursor: 'pointer', fontWeight: '600', fontSize: '0.8rem' }}>
                    Cancel
                  </button>
                )}
              </div>
            </div>
          ))}
        </div>
      )}

      {/* Payment Modal */}
      {selectedBooking && (
        <div style={{ position: 'fixed', inset: 0, background: 'rgba(0,0,0,0.7)', display: 'flex', alignItems: 'center', justifyContent: 'center', zIndex: 1000, padding: '1rem' }}>
          <div style={{ background: 'white', borderRadius: '20px', padding: '2rem', width: '100%', maxWidth: '420px' }}>
            <h2 style={{ fontWeight: '800', color: '#1e1b4b', marginBottom: '4px' }}>Complete Payment</h2>
            <p style={{ color: '#6b7280', fontSize: '0.85rem', marginBottom: '1.5rem' }}>{selectedBooking.event?.name}</p>

            <div style={{ background: '#f8f7ff', borderRadius: '12px', padding: '1rem', marginBottom: '1.5rem' }}>
              <div style={{ display: 'flex', justifyContent: 'space-between', color: '#6b7280', fontSize: '0.85rem', marginBottom: '6px' }}>
                <span>Tickets</span><span>{selectedBooking.numberOfTickets}</span>
              </div>
              <div style={{ display: 'flex', justifyContent: 'space-between', fontWeight: '800', color: '#1e1b4b', borderTop: '1px solid #e5e7eb', paddingTop: '8px' }}>
                <span>Total</span><span style={{ color: '#7c3aed' }}>₹{selectedBooking.totalAmount}</span>
              </div>
            </div>

            <p style={{ fontWeight: '700', color: '#374151', marginBottom: '10px', fontSize: '0.85rem' }}>Payment Method</p>
            <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '8px', marginBottom: '1.5rem' }}>
              {[{ value: 'card', icon: '💳', label: 'Card' }, { value: 'upi', icon: '📱', label: 'UPI' }, { value: 'netbanking', icon: '🏦', label: 'Net Banking' }, { value: 'wallet', icon: '👛', label: 'Wallet' }].map(m => (
                <button key={m.value} onClick={() => setPaymentMethod(m.value)} style={{
                  padding: '10px', borderRadius: '10px', border: `2px solid ${paymentMethod === m.value ? '#7c3aed' : '#e5e7eb'}`,
                  background: paymentMethod === m.value ? '#f5f3ff' : 'white',
                  color: paymentMethod === m.value ? '#7c3aed' : '#4b5563',
                  cursor: 'pointer', fontWeight: '600', fontSize: '0.8rem'
                }}>{m.icon} {m.label}</button>
              ))}
            </div>
            <div style={{ display: 'flex', gap: '10px' }}>
              <button onClick={() => setSelectedBooking(null)} style={{ flex: 1, background: '#f3f4f6', color: '#4b5563', border: 'none', padding: '12px', borderRadius: '10px', cursor: 'pointer', fontWeight: '600' }}>Cancel</button>
              <button onClick={handlePayment} disabled={paymentLoading} style={{ flex: 1, background: 'linear-gradient(135deg, #7c3aed, #a78bfa)', color: 'white', border: 'none', padding: '12px', borderRadius: '10px', cursor: 'pointer', fontWeight: '600', opacity: paymentLoading ? 0.6 : 1 }}>
                {paymentLoading ? '⏳ Processing...' : '✅ Pay Now'}
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}
export default MyBookings;
